INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-07770', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者最有可能不是助人者的情感反轉移癥候？', '["急於拯救案主，鼓勵案主依賴", "對案主毫無理由的討厭或被吸引", "案主的深層感受不予應有的重視或故意遺漏", "工作負荷過重，疲倦不堪，無法集中注意力"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07771', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '面對非自願案主時，下列何者較不易對社會工作人員造成兩難？', '["是幫助對方，或是成為社會控制的一環", "是符合案主的期待，或是符合機構的期待", "作為案主可依賴的朋友，或是受限於專業服務範圍的工作對象", "基於法律，釐清不可協商或可協商的空間"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07772', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '為了讓個案案主能自我決定（self-determination），下列何者是正確的？', '["案主的自決是基於案主能力為限，在特殊情況下，社會工作人員就不得不替代案主做決定", "社工要營造和諧信賴的工作環境，讓案主願意聽從社工的建議", "工作者將自助和訂定計畫的任務移轉到案主的家屬身上，由他們來協助案主改變其心理、社會功能", "刺激案主潛在的資源，引導其思考活動，引發其分辨能力，以致其最終可以不受個案工作者所掌控"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07773', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '以下何者較不是個案管理者的角色功能？', '["認知、連結案主及其所需資源，並追蹤之", "協調服務輸送體系", "對個案進行諮商或治療", "方案規劃、執行與評估"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07774', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '「你太太每次和你吵架，抱怨你太忙於工作，不關心家裡的事情，你是否想過她其實是在向你表達她需 要你的關心？」前述的例子說明社會工作人員在運用下列那一種會談技巧？', '["同理（empathy）", "反映（reflection）", "面質（confrontation）", "重新建構（reframing）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07775', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '針對次級創傷（secondary trauma）的陳述和說明，下列那一個答案是錯誤的？', '["工作性質、暴露在創傷事務中的程度和個人的情況等因素是造成社會工作人員次級創傷的原因", "社會工作人員懷疑自己所提供的一切服務是沒有用的，會變得沒有自信和無助；不敢結婚怕受虐；怕 小孩會得癌症而不敢生育等，這些都是次級創傷的一些症狀", "所有提供服務的社會工作人員都會有次級創傷的情況", "社會工作人員從事專業服務的時間尚短，卻可能會因人手不足、案量激增等因素，不得不投入災變、 兒少保護、受暴等性質的工作，也可能因缺乏有足夠經驗資深社工督導的指導與協助等各種因素，較 易受到次級創傷而離開工作崗位"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07776', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '倫理議題可區分為①違背倫理守則事例②倫理兩難事例等類型。請依序說明下列五個例子分別屬於那一種類 型的倫理議題？例一：「甲社會工作師將執業執照借給好友開設的托兒所，本人其實未在該托兒所工作。」 例二：「佳佳未成年，與網友發生戀情而懷孕，請求乙社會工作師不要告知父母，否則離家出走。」例三： 「呂太太以種菜為生，很感激丙社會工作師的幫助，每次見面都贈送丙社會工作師大把自種的蔬菜。」 例四：「毛毛因故殺害其女友，並向丁社會工作師告白，當警方查案時，丁社會工作師拒絕透露消息。」 例五：「王先生夫妻已80歲，住在平價住宅多年，因低收入戶資格註銷，戊社會工作師通知必須遷出， 但王先生夫妻以死明志，強迫遷出就自殺。」', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07777', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '失業的案主請求社會工作人員協助恢復就業，為了瞭解服務成效，他們一起討論預期的成果，分別為： 接受工作面試，找到月薪8,000元的工作，找到月薪16,000元的工作，找到月薪24,000元的工作，找到 月薪32,000元的工作。請問此種結果評估是屬於下列那一種？', '["成本效率分析（cost efficiency analysis）", "成本效益分析（cost benefit analysis）", "目標達成尺度（goal attainment scaling）", "自我錨定與排列法（self-anchored and rating scales）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07778', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '案主是一位單親媽媽，有三個孩子，為了維持生計，非常努力工作，平時孩子的照顧有外婆的協助，現 請求兒童福利機構協助孩子的課業輔導。請問以上的敘述是屬於下列那一部分的預估（assessment）？', '["案主表達有潛藏的多重問題", "有法令規定中需要介入的情境", "案主否認有任何問題", "案主擁有潛在的支持和資源"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07779', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作人員需要扮演各種角色以協助案主獲得所需要的服務。下列那一項敘述是錯誤的？', '["社會工作人員除提供案主心理和物質上的協助外，同時也協助案主及其家人接受其他機構的相關服務。 此時社會工作人員扮演個案管理者和媒介者的角色", "當社會缺乏案主所需要的資源體系時，社會工作人員就必須扮演方案發展者和推動者的角色", "社會工作人員評估自己機構或其他機構的服務政策和過程，是否有讓案主無謂的等待，案主申請服務 的程序是否過於繁雜，工作人員是否尊重案主，服務過程中是否能有效協助案主取得服務資源等。此 時社會工作人員扮演倡導者的角色", "社會工作人員經常透過協助案主取得所需資源的過程，而達到促進案主自我決定的專業目標。此時社 會工作人員扮演使能者的角色"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "430760892fcc", "answer_pdf_sha1": "2d91d4742310", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
